## 4. Writing Output Files

Generators must write files themselves using Node.js APIs.

### From `client-generator-ts/src/generateClient.ts`:

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import { ensureDir } from 'fs-extra'

export async function generateClient(options: GenerateClientOptions): Promise<void> {
  const outputDir = getOutputPath(options.generator)

  // Clear output directory
  await deleteOutputDir(outputDir)
  await ensureDir(outputDir)

  // Build file map structure
  const fileMap = {
    'client.ts': '/* generated code */',
    'enums.ts': '/* enum definitions */',
    'models': {
      'User.ts': '/* User model */',
      'Post.ts': '/* Post model */',
    },
    'internal': {
      'prismaNamespace.ts': '/* internals */',
    }
  }

  // Write files recursively
  await writeFileMap(outputDir, fileMap)
}

function writeFileMap(outputDir: string, fileMap: FileMap) {
  return Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)

      if (typeof content === 'string' || Buffer.isBuffer(content)) {
        // Write file
        await fs.writeFile(absolutePath, content)
      } else {
        // Create subdirectory and recurse
        await fs.mkdir(absolutePath)
        await writeFileMap(absolutePath, content)
      }
    })
  )
}
```

**Key Points:**
1. Get output path: `parseEnvValue(options.generator.output)`
2. Use `fs/promises` for modern async APIs
3. Use `fs-extra` for `ensureDir()`
4. Write relative to `outputDir`, building nested directories as needed

