## 5. Using @prisma/ts-builders for TypeScript AST

The `@prisma/ts-builders` package builds TypeScript code programmatically.

### Location:
- **`packages/ts-builders/src/`** - Full AST builder library

### Basic Usage

```typescript
import * as ts from '@prisma/ts-builders'

// Build a type declaration
const userType = ts.objectType()
  .addProperty(ts.property('id', ts.namedType('string')).id())
  .addProperty(ts.property('name', ts.namedType('string')))
  .addProperty(ts.property('email', ts.namedType('string')).optional())

const typeDecl = ts.typeDeclaration('User', userType)

// Convert to string
const code = ts.stringify(typeDecl)
// Output: "type User = { id: string; name: string; email?: string }"
```

### Common Builders

```typescript
// Types
ts.namedType('string')
ts.unionType([ts.namedType('A'), ts.namedType('B')])
ts.intersectionType([...])
ts.array(ts.namedType('string'))
ts.objectType().addProperty(...)
ts.nullType
ts.literal('value')

// Declarations
ts.typeDeclaration(name, type)
ts.interface(name).addProperty(...)
ts.property(name, type).optional()

// Imports/Exports
ts.moduleImport(path).asNamespace('name')
ts.export(typeDecl)

// Utilities
ts.stringify(node)
ts.docComment().addText('...')
```

### Pattern from client-generator-ts

```typescript
import * as ts from '@prisma/ts-builders'
import { GenerateContext } from './GenerateContext'

export function createModelFile(context: GenerateContext, modelName: string): string {
  const jsDocHeader = `/* Model: ${modelName} */`

  const imports = [
    ts.moduleImport('@prisma/client/runtime').asNamespace('runtime').typeOnly(),
  ]
  const importsString = imports.map(i => ts.stringify(i)).join('\n')

  const model = context.dmmf.typeAndModelMap[modelName]

  // Build model type from DMMF
  const modelType = buildModelType(model)

  return jsDocHeader + importsString + '\n' + ts.stringify(modelType)
}

function buildModelType(model: DMMF.Model): ts.TypeBuilder {
  const type = ts.objectType()

  for (const field of model.fields) {
    const fieldType = getFieldType(field)
    const prop = ts.property(field.name, fieldType)

    if (!field.isRequired) {
      prop.optional()
    }

    type.addProperty(prop)
  }

  return type
}
```

