  get typeAndModelMap(): Dictionary<DMMF.Model>     // By name
  get mappingsMap(): Dictionary<DMMF.ModelMapping>  // By model name
  get outputTypeMap(): { model, prisma }            // By namespace
  get rootFieldMap(): Dictionary<DMMF.SchemaField>  // Query/Mutation fields

  // Utilities
  isComposite(name: string): boolean
  hasEnumInNamespace(name: string, ns: FieldNamespace): boolean
