## 9. Complete Example: Simple Generator

```typescript
// generator.ts
import { generatorHandler } from '@prisma/generator-helper'
import type { GeneratorOptions, GeneratorManifest, GeneratorConfig } from '@prisma/generator'
import * as DMMF from '@prisma/dmmf'
import * as ts from '@prisma/ts-builders'
import fs from 'node:fs/promises'
import path from 'node:path'
import { parseEnvValue } from '@prisma/internals'

generatorHandler({
  onManifest: async (config: GeneratorConfig) => ({
    defaultOutput: './generated',
    prettyName: 'Model Exporter',
  } as GeneratorManifest),

  onGenerate: async (options: GeneratorOptions) => {
    const outputDir = parseEnvValue(options.generator.output)
    await fs.mkdir(outputDir, { recursive: true })

    // Generate a file with all model names and fields
    const content = generateModelIndex(options.dmmf)
    await fs.writeFile(path.join(outputDir, 'models.ts'), content)
  },
})

function generateModelIndex(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push('// Auto-generated model index')
  lines.push('')

  for (const model of dmmf.datamodel.models) {
    lines.push(`export type ${model.name} = {`)

    for (const field of model.fields) {
      let fieldType = field.type
      if (field.kind === 'object') {
        fieldType = `${field.type} | null` // relation
      }
      if (field.isList) fieldType += '[]'
      if (!field.isRequired) fieldType += ' | null'

      lines.push(`  ${field.name}: ${fieldType}`)
    }

    lines.push('}')
    lines.push('')
  }

  return lines.join('\n')
}
```

