import type * as DMMF from '@prisma/dmmf'

import { mapPrismaScalarToTs } from './type-mapper'

/**
 * Returns the base TypeScript type for a field (without nullability wrapper).
 * Scalar fields are mapped via `mapPrismaScalarToTs`; enum and relation fields
 * use the Prisma type name directly as a TypeScript identifier.
 */
function fieldBaseTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = mapPrismaScalarToTs(field.type)
  } else {
    base = field.type
  }
  return field.isList ? `${base}[]` : base
}

/**
 * Returns the full TypeScript type for a field including the `| null` suffix
 * for optional (non-required) fields.
 */
function fieldTsType(field: DMMF.Field): string {
  const base = fieldBaseTsType(field)
  return field.isRequired ? base : `${base} | null`
}

/**
 * Generates the complete TypeScript source for a single Prisma model:
 * a data interface, input types for CRUD operations, and a typed REST client class.
 */
export function buildModelFile(model: DMMF.Model): string {
  const { name } = model

  const scalarAndEnumFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const idField = model.fields.find((f) => f.isId)
  const idFieldName = idField?.name ?? 'id'
  const idTsType = idField ? fieldBaseTsType(idField) : 'string'
  const resourcePath = name.toLowerCase()

  const interfaceLines = scalarAndEnumFields.map((f) => `  ${f.name}: ${fieldTsType(f)};`).join('\n')

  const whereUniqueLines = `  ${idFieldName}: ${idTsType};`

  const createInputLines = scalarAndEnumFields
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue || !!f.isGenerated
      return `  ${f.name}${optional ? '?' : ''}: ${fieldBaseTsType(f)};`
    })
    .join('\n')

  const updateInputLines = scalarAndEnumFields.map((f) => `  ${f.name}?: ${fieldBaseTsType(f)};`).join('\n')

  const findManyArgsLines = [
    `  where?: Partial<${name}>;`,
    `  skip?: number;`,
    `  take?: number;`,
    `  orderBy?: Partial<Record<keyof ${name}, 'asc' | 'desc'>>;`,
  ].join('\n')

  return `\
export interface ${name} {
${interfaceLines}
}

export interface ${name}WhereUniqueInput {
${whereUniqueLines}
}

export interface ${name}CreateInput {
${createInputLines}
}

export interface ${name}UpdateInput {
${updateInputLines}
}

export interface ${name}FindManyArgs {
${findManyArgsLines}
}

export class ${name}RestClient {
  readonly #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(args?: ${name}FindManyArgs): Promise<${name}[]> {
    const params = new URLSearchParams()
    if (args?.skip !== undefined) params.set('skip', String(args.skip))
    if (args?.take !== undefined) params.set('take', String(args.take))
    const query = params.size > 0 ? \`?\${params}\` : ''
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}\${query}\`)
    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${where.${idFieldName}}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${where.${idFieldName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const res = await fetch(\`\${this.#baseUrl}/${resourcePath}/\${where.${idFieldName}}\`, {
      method: 'DELETE',
    })
    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.status}\`)
    return res.json() as Promise<${name}>
  }
}
`
}

