import type * as DMMF from '@prisma/dmmf'

/** Lowercases the first character of a string. */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generates the root `index.ts` that re-exports all per-model files and
 * provides an aggregated `RestApiClient` class with one property per model.
 */
export function buildIndexFile(models: readonly DMMF.Model[]): string {
  const modelNames = models.map((m) => m.name)

  const reExports = modelNames.map((n) => `export * from './${n}'`).join('\n')

  const modelImports = modelNames.map((n) => `import { ${n}RestClient } from './${n}'`).join('\n')

  const clientFields = modelNames.map((n) => `  readonly ${lcFirst(n)}: ${n}RestClient`).join('\n')

  const constructorBody = modelNames
    .map((n) => `    this.${lcFirst(n)} = new ${n}RestClient(baseUrl)`)
    .join('\n')

  return `\
${reExports}

${modelImports}

/** Aggregated REST client with one accessor per Prisma model. */
export class RestApiClient {
${clientFields}

  constructor(baseUrl: string) {
${constructorBody}
  }
}
`
}

