import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { buildIndexFile } from './index-file-builder'
import { buildModelFile } from './model-file-builder'

/**
 * Writes all generated REST client files to `outputDir`.
 * Creates the directory (and any missing parents) if it does not already exist.
 */
export async function generateClient(dmmf: DMMF.Document, outputDir: string): Promise<void> {
  await fs.mkdir(outputDir, { recursive: true })

  const { models } = dmmf.datamodel

  await Promise.all(
    models.map(async (model) => {
      const content = buildModelFile(model)
      await fs.writeFile(path.join(outputDir, `${model.name}.ts`), content, 'utf-8')
    }),
  )

  const indexContent = buildIndexFile(models)
  await fs.writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8')
}

