import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { buildModelFile } from '../src/model-file-builder'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'age', type: 'Int' }),
    makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

describe('buildModelFile', () => {
  it('generates a TypeScript interface for the model', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export interface User {')
    expect(output).toContain('id: string;')
    expect(output).toContain('email: string;')
    expect(output).toContain('name: string | null;')
    expect(output).toContain('age: number;')
    expect(output).toContain('createdAt: Date;')
  })

  it('generates WhereUniqueInput using the @id field', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('id: string;')
  })

  it('makes fields with default values optional in CreateInput', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export interface UserCreateInput {')
    // id has a default value so it is optional
    expect(output).toContain('id?: string;')
    // createdAt has a default value so it is optional
    expect(output).toContain('createdAt?: Date;')
    // email is required with no default, so it is required
    expect(output).toContain('email: string;')
  })

  it('makes all fields optional in UpdateInput', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('id?: string;')
    expect(output).toContain('email?: string;')
    expect(output).toContain('name?: string;')
  })

  it('generates FindManyArgs with pagination and filter fields', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export interface UserFindManyArgs {')
    expect(output).toContain('where?: Partial<User>;')
    expect(output).toContain('skip?: number;')
    expect(output).toContain('take?: number;')
    expect(output).toContain("orderBy?: Partial<Record<keyof User, 'asc' | 'desc'>>;")
  })

  it('generates a REST client class with all CRUD methods', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('export class UserRestClient {')
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  it('uses the lowercased model name as the REST resource path', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('`${this.#baseUrl}/user`')
    expect(output).toContain('`${this.#baseUrl}/user/${where.id}`')
  })

  it('returns 404 as null from findUnique', () => {
    const output = buildModelFile(userModel)
    expect(output).toContain('if (res.status === 404) return null')
  })

  it('falls back to "id: string" when no @id field is present', () => {
    const modelWithoutId: DMMF.Model = {
      ...userModel,
      name: 'Log',
      fields: [makeField({ name: 'message', type: 'String' })],
    }
    const output = buildModelFile(modelWithoutId)
    expect(output).toContain('id: string;')
  })
})

